async (page) => {
  // Check equipped items via game API
  const equipped = await page.evaluate(() => {
    try {
      const player = window.game.player;
      // Try to get equipment info
      const equip = player.equipment;
      if (equip) {
        const result = {};
        const slots = ['weapon', 'armour', 'pendant', 'ring', 'boots'];
        slots.forEach(s => {
          if (equip[s]) result[s] = equip[s].key || equip[s].name || 'unknown';
        });
        return JSON.stringify(result);
      }
      return 'no equipment object';
    } catch(e) { return 'error: ' + e.message; }
  });
  return 'Equipped: ' + equipped;
}

