async (page) => {
  const result = await page.evaluate(() => {
    const p = window.game.player;
    // Try different ways to check equipped weapon
    const weapon = p.getWeapon ? p.getWeapon() : null;
    const weaponSlot = p.equipment ? p.equipment.weapon : null;

    // Check the DOM for equipped items
    const equipSlots = Array.from(document.querySelectorAll('.equipment-slot')).map(s => s.innerHTML.trim().substring(0,100));

    // Check inventory through game
    const inv = p.inventory;
    const invItems = inv ? (inv.slots || []).map((s,i) => s && s.key ? {slot:i, key:s.key, name:s.name} : null).filter(Boolean) : [];

    return JSON.stringify({
      weaponKey: weapon ? weapon.key : 'none',
      weaponName: weapon ? weapon.name : 'none',
      equipSlots: equipSlots.slice(0,5),
      invItems
    });
  });
  return result;
}

async (page) => {
  const result = await page.evaluate(() => {
    const p = window.game.player;
    // Check skills through player object
    const skills = {};
    if (p.skills) {
      Object.keys(p.skills).forEach(key => {
        const skill = p.skills[key];
        if (skill && skill.level !== undefined) {
          skills[key] = { level: skill.level, experience: skill.experience };
        }
      });
    }
    // Also try skill manager
    const sm = p.skill || p.skillManager;
    return JSON.stringify({ skills, level: p.level, experience: p.experience });
  });
  return result;
}

