async (page) => {
  const data = await page.evaluate(() => {
    try {
      // Check game map for portals/doors
      const map = window.game.map;
      const portals = map.portals || map.warps || [];
      const doors = map.doors || [];

      // Check player's current area/zone
      const region = window.game.player ? window.game.player.region : null;
      const area = window.game.player ? window.game.player.moving : null;

      // Try to find any nearby interactable tiles
      const pos = window.__latestGameState.player_position;
      const entrances = [];

      // Check around player (radius 15) for warp/door tiles
      if (map.getObject) {
        for (let dy = -5; dy <= 10; dy++) {
          for (let dx = -5; dx <= 20; dx++) {
            const obj = map.getObject(pos.x + dx, pos.y + dy);
            if (obj && obj.portal) {
              entrances.push({x: pos.x+dx, y: pos.y+dy, obj});
            }
          }
        }
      }

      return JSON.stringify({
        portals: portals.slice ? portals.slice(0,10) : Object.keys(portals||{}).slice(0,10),
        doors: doors.slice ? doors.slice(0,10) : Object.keys(doors||{}).slice(0,10),
        pos: pos,
        entrances: entrances.slice(0,10)
      });
    } catch(e) {
      return JSON.stringify({error: e.message});
    }
  });
  return data;
}

async (page) => {
  const data = await page.evaluate(() => {
    const mapGrid = window.game.map.grids.map;
    const grid = mapGrid.grid; // [y][x] array, 1=blocked

    // Check grid for y=220-235, x=148-175
    // Find where we can pass through
    const results = [];
    for (let y = 220; y <= 235; y++) {
      if (!grid[y]) continue;
      const row = Array.from(grid[y]).slice(148, 175);
      results.push({y, values: row.map((v,i) => v ? 'X' : '.').join(''), raw: row});
    }
    return JSON.stringify(results);
  });

  // Parse and display in readable format
  const rows = JSON.parse(data);
  let output = 'y   x=148...175\n';
  for (const r of rows) {
    output += `${r.y}: ${r.values}\n`;
  }
  return output;
}

